package cmd

import (
	"encoding/json"
	"fmt"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/spf13/cobra"
)

// newBeadDoctorCommand wires `ddx bead doctor` / `ddx bead doctor --fix`.
//
// Scan mode (no flags): exits non-zero if any field on any bead exceeds the
// per-field cap (ddx-f8a11202) or if a dependency points back into the bead's
// parent chain. Safe to run on any tree — no mutations.
//
// Fix mode (--fix): rewrites oversized fields in place and removes dependency
// edges that point back into the bead's parent chain. Before touching the
// tracker the command writes a timestamped backup under .ddx/backups/ so
// the original file is always recoverable. Overflow content persists as
// artifacts under .ddx/executions/<bead-id>/repair-<timestamp>/ and a
// repair event is appended to each rewritten bead. Idempotent — the second
// invocation exits 0 without writing because the scan is clean.
//
// Dangling-success mode (--dangling): detects in_progress beads whose last
// execution produced task_succeeded but CloseWithEvidence never ran. Safe
// to run on any tree — no mutations unless --fix is also passed.
// (ddx-2b2d114e)
func (f *CommandFactory) newBeadDoctorCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "doctor",
		Short: "Detect (and optionally repair) beads.jsonl rows with oversized fields or back-edge deps",
		Long: `Scan the bead tracker for fields that exceed the per-field size cap.

Bead fields (description, acceptance, notes, events[].body, events[].summary)
are capped at 65,535 bytes so DDx-authored beads round-trip cleanly through
bd import (upstream's Dolt TEXT column limit). Fields over the cap usually
come from a writer bug that landed before the cap was enforced — for
example a reviewer stream dumped verbatim into an event body.

The doctor also scans for dependency edges whose targets appear in the bead's
parent chain. Those findings are reported as parent_ancestor_in_deps and
--fix removes only the offending edges, leaving the rest of the dependency
list untouched.

Without --fix this command only reports offending rows and exits non-zero.
With --fix it:

  1. Writes a timestamped backup to .ddx/backups/ before any mutation.
  2. Truncates each oversized field to the cap using head+tail+marker.
  3. Writes the full original payload for truncated fields to
     .ddx/executions/<bead>/repair-<timestamp>/<field>.log so forensics
     remain possible.
  4. Removes dependency edges that point back into the bead's parent chain.
  5. Appends a kind=repair event to every rewritten bead.

Idempotent: once a tracker is clean, running --fix again is a no-op.

With --dangling: scan for in_progress beads whose last execution produced
task_succeeded but whose bead-close step never ran (dangling-success).
For each finding, reports whether result_rev is reachable from HEAD:
  - reachable=true:  merge succeeded, close didn't. Safe to close manually
    with: ddx bead close <bead-id>
  - reachable=false: the merge itself was never applied (dangling commit).
    The result_rev is shown for manual git cherry-pick or re-attempt.
(ddx-2b2d114e)`,
		RunE: func(cmd *cobra.Command, args []string) error {
			workspace := f.beadWorkspaceRoot()
			if workspace == "" {
				return fmt.Errorf("bead doctor: no .ddx workspace found")
			}
			path := ddxroot.JoinProject(workspace, "beads.jsonl")

			doFix, _ := cmd.Flags().GetBool("fix")
			asJSON, _ := cmd.Flags().GetBool("json")
			doDangling, _ := cmd.Flags().GetBool("dangling")

			// --dangling mode: detect dangling-success beads (ddx-2b2d114e).
			if doDangling {
				findings, err := agent.DetectDanglingSuccessBeads(workspace)
				if err != nil {
					return fmt.Errorf("bead doctor --dangling: %w", err)
				}
				if asJSON {
					enc := json.NewEncoder(cmd.OutOrStdout())
					enc.SetIndent("", "  ")
					return enc.Encode(struct {
						Clean    bool                           `json:"clean"`
						Findings []agent.DanglingSuccessFinding `json:"findings"`
					}{
						Clean:    len(findings) == 0,
						Findings: findings,
					})
				}
				out := cmd.OutOrStdout()
				if len(findings) == 0 {
					fmt.Fprintf(out, "bead doctor --dangling: clean (no dangling-success beads detected)\n")
					return nil
				}
				fmt.Fprintf(out, "bead doctor --dangling: %d finding(s):\n", len(findings))
				for _, fi := range findings {
					reachableStr := "reachable=false (dangling commit — merge never applied)"
					recovery := "  recovery: git cherry-pick or re-run ddx try " + fi.BeadID
					if fi.Reachable {
						reachableStr = "reachable=true (merge succeeded, close didn't run)"
						recovery = "  recovery: ddx bead close " + fi.BeadID + "  # or re-run ddx try"
					}
					fmt.Fprintf(out, "  %s  attempt=%s  result_rev=%s\n    %s\n%s\n",
						fi.BeadID, fi.AttemptID, fi.ResultRev, reachableStr, recovery)
				}
				return fmt.Errorf("bead doctor --dangling: %d finding(s) detected", len(findings))
			}

			var report bead.DoctorReport
			var err error
			if doFix {
				report, err = bead.BeadDoctorFix(path, nil)
			} else {
				report, err = bead.BeadDoctor(path)
			}
			if err != nil {
				return err
			}

			if asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(struct {
					Path     string               `json:"path"`
					Fixed    bool                 `json:"fixed"`
					Clean    bool                 `json:"clean"`
					Findings []bead.DoctorFinding `json:"findings"`
				}{
					Path:     report.Path,
					Fixed:    doFix && !report.Clean(),
					Clean:    report.Clean(),
					Findings: report.Findings,
				})
			}

			out := cmd.OutOrStdout()
			if report.Clean() {
				fmt.Fprintf(out, "bead doctor: %s — clean (no oversized fields or parent-ancestor deps detected)\n", path)
				return nil
			}
			fmt.Fprintf(out, "bead doctor: %s — %d finding(s):\n", path, len(report.Findings))
			for _, f := range report.Findings {
				fmt.Fprintln(out, formatBeadDoctorFinding(f))
			}
			if doFix {
				fmt.Fprintf(out, "\nrepair complete. backup written to %s/backups/.\n", filepath.Dir(path))
				if hasBeadDoctorKind(report.Findings, "oversized_field") {
					fmt.Fprintf(out, "truncated fields were captured under %s/executions/<bead>/repair-*/\n", filepath.Dir(path))
				}
				return nil
			}
			// Non-fix scan: non-zero exit via cobra error so CI can catch it.
			return fmt.Errorf("bead doctor: %d finding(s) — run `ddx bead doctor --fix` to repair", len(report.Findings))
		},
	}
	cmd.Flags().Bool("fix", false, "Rewrite oversized fields in place after writing a backup")
	cmd.Flags().Bool("json", false, "Output findings as JSON")
	cmd.Flags().Bool("dangling", false, "Detect in_progress beads with a prior task_succeeded result (dangling-success, ddx-2b2d114e)")
	return cmd
}

func formatBeadDoctorFinding(f bead.DoctorFinding) string {
	switch f.Kind {
	case "parent_ancestor_in_deps":
		chain := f.SampleHead
		if len(f.ParentChain) > 0 {
			chain = strings.Join(f.ParentChain, " -> ")
		}
		return fmt.Sprintf("  %s  %s  %s  dependency=%s  ancestor=%s  chain=%s", f.BeadID, f.Kind, f.FieldPath, f.DependencyID, f.AncestorID, chain)
	case "unparseable_line":
		return fmt.Sprintf("  %s  %s  size=%d  head=%q", f.BeadID, f.Kind, f.SizeBytes, f.SampleHead)
	default:
		return fmt.Sprintf("  %s  %s  %s  %d bytes  head=%q", f.BeadID, f.Kind, f.FieldPath, f.SizeBytes, f.SampleHead)
	}
}

func hasBeadDoctorKind(findings []bead.DoctorFinding, kind string) bool {
	for _, f := range findings {
		if f.Kind == kind {
			return true
		}
	}
	return false
}

package bead

import (
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"
)

const (
	doctorFindingKindOversizedField       = "oversized_field"
	doctorFindingKindParentAncestorInDeps = "parent_ancestor_in_deps"
	doctorFindingKindUnparseableLine      = "unparseable_line"
)

// DoctorFinding reports a single bead doctor issue. Findings cover oversized
// field values, dependency edges that point back into the bead's parent chain,
// and line-level parse failures.
type DoctorFinding struct {
	Kind         string   `json:"kind,omitempty"`
	BeadID       string   `json:"bead_id"`
	FieldPath    string   `json:"field_path"`
	TargetID     string   `json:"target_id,omitempty"`
	DependencyID string   `json:"dependency_id,omitempty"`
	AncestorID   string   `json:"ancestor_id,omitempty"`
	ParentChain  []string `json:"parent_chain,omitempty"`
	SizeBytes    int      `json:"size_bytes,omitempty"`
	SampleHead   string   `json:"sample_head,omitempty"`
}

// DoctorReport is the output of BeadDoctor — an ordered list of findings.
type DoctorReport struct {
	Path     string
	Findings []DoctorFinding
}

// Clean is true when there are no findings.
func (r DoctorReport) Clean() bool { return len(r.Findings) == 0 }

type doctorRow struct {
	lineNo   int
	rawLine  []byte
	raw      map[string]any
	bead     *Bead
	parseErr error
}

func loadDoctorRows(path string) ([]doctorRow, error) {
	src, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}

	lines := bytes.Split(src, []byte{'\n'})
	rows := make([]doctorRow, 0, len(lines))
	for i, line := range lines {
		trimmed := bytes.TrimSpace(line)
		if len(trimmed) == 0 {
			continue
		}
		row := doctorRow{
			lineNo:  i + 1,
			rawLine: append([]byte(nil), line...),
		}
		if err := json.Unmarshal(trimmed, &row.raw); err != nil {
			row.parseErr = err
			rows = append(rows, row)
			continue
		}
		bead, err := unmarshalBead(trimmed)
		if err != nil {
			row.parseErr = err
			rows = append(rows, row)
			continue
		}
		row.bead = &bead
		rows = append(rows, row)
	}
	return rows, nil
}

// BeadDoctor scans a beads.jsonl file and returns every oversized field and
// every dependency edge that points back into the bead's parent chain.
// Lines that fail to parse are reported as a single finding with
// Kind=unparseable_line and the raw line as the sample.
func BeadDoctor(path string) (DoctorReport, error) {
	report := DoctorReport{Path: path}
	rows, err := loadDoctorRows(path)
	if err != nil {
		return report, err
	}

	byID := make(map[string]*Bead, len(rows))
	for _, row := range rows {
		if row.bead == nil || row.bead.ID == "" {
			continue
		}
		byID[row.bead.ID] = row.bead
	}

	for _, row := range rows {
		if row.parseErr != nil {
			report.Findings = append(report.Findings, DoctorFinding{
				Kind:       doctorFindingKindUnparseableLine,
				BeadID:     fmt.Sprintf("line %d (unparseable)", row.lineNo),
				FieldPath:  "line",
				SizeBytes:  len(bytes.TrimSpace(row.rawLine)),
				SampleHead: firstN(string(bytes.TrimSpace(row.rawLine)), 80),
			})
			continue
		}
		if row.bead == nil {
			continue
		}
		report.Findings = append(report.Findings, oversizedFieldFindings(row.bead)...)
		report.Findings = append(report.Findings, parentAncestorDepFindings(row.bead, byID)...)
	}

	sortDoctorFindings(report.Findings)
	return report, nil
}

func oversizedFieldFindings(b *Bead) []DoctorFinding {
	findings := make([]DoctorFinding, 0, 5)
	if b == nil {
		return findings
	}
	for _, field := range []string{"description", "acceptance", "notes"} {
		if s := beadFieldString(b, field); len(s) > MaxFieldBytes {
			findings = append(findings, DoctorFinding{
				Kind:       doctorFindingKindOversizedField,
				BeadID:     b.ID,
				FieldPath:  field,
				SizeBytes:  len(s),
				SampleHead: firstN(s, 80),
			})
		}
	}
	for i, ev := range decodeBeadEvents(b.Extra["events"]) {
		for _, field := range []string{"body", "summary"} {
			if s := beadEventString(ev, field); len(s) > MaxFieldBytes {
				findings = append(findings, DoctorFinding{
					Kind:       doctorFindingKindOversizedField,
					BeadID:     b.ID,
					FieldPath:  fmt.Sprintf("events[%d].%s", i, field),
					SizeBytes:  len(s),
					SampleHead: firstN(s, 80),
				})
			}
		}
	}
	return findings
}

func beadFieldString(b *Bead, field string) string {
	switch field {
	case "description":
		return b.Description
	case "acceptance":
		return b.Acceptance
	case "notes":
		return b.Notes
	default:
		return ""
	}
}

func beadEventString(ev BeadEvent, field string) string {
	switch field {
	case "body":
		return ev.Body
	case "summary":
		return ev.Summary
	default:
		return ""
	}
}

func parentAncestorDepFindings(b *Bead, byID map[string]*Bead) []DoctorFinding {
	if b == nil {
		return nil
	}
	chain, _ := beadParentChain(byID, b.Parent)
	if len(chain) == 0 || len(b.Dependencies) == 0 {
		return nil
	}
	ancestorSet := make(map[string]struct{}, len(chain))
	for _, ancestorID := range chain {
		ancestorSet[ancestorID] = struct{}{}
	}

	findings := make([]DoctorFinding, 0, len(b.Dependencies))
	for i, dep := range b.Dependencies {
		if _, ok := ancestorSet[dep.DependsOnID]; !ok {
			continue
		}
		findings = append(findings, DoctorFinding{
			Kind:         doctorFindingKindParentAncestorInDeps,
			BeadID:       b.ID,
			FieldPath:    fmt.Sprintf("dependencies[%d].depends_on_id", i),
			TargetID:     dep.DependsOnID,
			DependencyID: dep.DependsOnID,
			AncestorID:   dep.DependsOnID,
			ParentChain:  append([]string(nil), chain...),
			SampleHead:   strings.Join(chain, " -> "),
		})
	}
	return findings
}

func sortDoctorFindings(findings []DoctorFinding) {
	sort.SliceStable(findings, func(i, j int) bool {
		if findings[i].BeadID != findings[j].BeadID {
			return findings[i].BeadID < findings[j].BeadID
		}
		if doctorFindingKindRank(findings[i].Kind) != doctorFindingKindRank(findings[j].Kind) {

package bead

import (
	"fmt"
	"strings"
)

// LifecycleTransitionOptions contains the explicit facts required to validate
// status changes whose meaning would otherwise be implicit in caller policy.
type LifecycleTransitionOptions struct {
	OperatorRequired      bool
	ExternalBlockerReason string
	ManualClose           bool
	ManualReopen          bool
	Reason                string
	Actor                 string
	Source                string
}

// LifecycleDependencyState is the small dependency shape the pure lifecycle
// core needs. Store callers can adapt richer dependency records into this type.
type LifecycleDependencyState struct {
	Status string
}

// LifecycleQueueFacts contains all queue-classification inputs as caller-owned
// facts. It deliberately avoids store access, filesystem access, configuration,
// process execution, git access, and clock reads.
type LifecycleQueueFacts struct {
	Status                  string
	Dependencies            []LifecycleDependencyState
	ClaimFresh              bool
	RetryCooldownActive     bool
	ExecutionEligible       bool
	ExecutionEligibleKnown  bool
	SupersededBy            string
	EpicContainer           bool
	ExternalBlockerReason   string
	LegacyLabels            []string
	LegacyMigrationWarnings []string
}

// LifecycleQueueBucket is the derived queue state used by dispatch, review,
// and operator-facing views. It is not persisted as bead.Status.
type LifecycleQueueBucket string

const (
	LifecycleBucketReady               LifecycleQueueBucket = "ready"
	LifecycleBucketWaitingDependencies LifecycleQueueBucket = "waiting_dependencies"
	LifecycleBucketProposed            LifecycleQueueBucket = "proposed"
	LifecycleBucketClaimed             LifecycleQueueBucket = "claimed"
	LifecycleBucketBlockedExternal     LifecycleQueueBucket = "blocked_external"
	LifecycleBucketClosedTerminal      LifecycleQueueBucket = "closed_terminal"
	LifecycleBucketCancelledTerminal   LifecycleQueueBucket = "cancelled_terminal"
	LifecycleBucketRetryCooldown       LifecycleQueueBucket = "retry_cooldown"
	LifecycleBucketNotEligible         LifecycleQueueBucket = "not_eligible"
	LifecycleBucketSuperseded          LifecycleQueueBucket = "superseded"
	LifecycleBucketEpicContainer       LifecycleQueueBucket = "epic_container"
	LifecycleBucketInvalid             LifecycleQueueBucket = "invalid"
)

// LifecycleIssueCode identifies validation findings from pure lifecycle
// evaluation. Issues explain bad facts; they do not mutate status or labels.
type LifecycleIssueCode string

const (
	LifecycleIssueInvalidStatus                LifecycleIssueCode = "invalid_status"
	LifecycleIssueBlockedMissingExternalReason LifecycleIssueCode = "blocked_missing_external_reason"
	LifecycleIssueTransitionRequiresOperator   LifecycleIssueCode = "transition_requires_operator"
	LifecycleIssueTransitionRequiresExternal   LifecycleIssueCode = "transition_requires_external_blocker"
	LifecycleIssueTransitionFromTerminal       LifecycleIssueCode = "transition_from_terminal"
	LifecycleIssueTransitionUnsupported        LifecycleIssueCode = "transition_unsupported"
	LifecycleIssueLegacyLabelLifecycleMetadata LifecycleIssueCode = "legacy_label_lifecycle_metadata"
	LifecycleIssueLegacyMigrationCompatibility LifecycleIssueCode = "legacy_migration_compatibility"
)

// LifecycleIssue is a deterministic, caller-displayable finding.
type LifecycleIssue struct {
	Code   LifecycleIssueCode
	Detail string
}

// LifecycleQueueDecision is the pure result of evaluating LifecycleQueueFacts.
type LifecycleQueueDecision struct {
	Bucket                LifecycleQueueBucket
	WorkerEligible        bool
	OperatorAttention     bool
	DependenciesSatisfied bool
	SatisfiesDependents   bool
	Issues                []LifecycleIssue
	Warnings              []string
	ExternalBlockerReason string
}

// ValidateLifecycleTransition returns nil when from -> to is a valid persisted
// status transition under the supplied explicit facts.
func ValidateLifecycleTransition(from, to string, opts LifecycleTransitionOptions) error {
	if err := validateLifecycleStatus(from); err != nil {
		return err
	}
	if err := validateLifecycleStatus(to); err != nil {
		return err
	}
	if from == to {
		return nil
	}
	if to == StatusClosed && opts.ManualClose {
		switch from {
		case StatusOpen, StatusInProgress, StatusBlocked, StatusProposed:
			return nil
		}
	}
	if from == StatusClosed && to == StatusOpen && opts.ManualReopen {
		return nil
	}
	if from == StatusClosed || from == StatusCancelled {
		return lifecycleTransitionError(LifecycleIssueTransitionFromTerminal, from, to)
	}
	if to == StatusProposed && !opts.OperatorRequired {
		return lifecycleTransitionError(LifecycleIssueTransitionRequiresOperator, from, to)
	}
	if to == StatusBlocked && strings.TrimSpace(opts.ExternalBlockerReason) == "" {
		return lifecycleTransitionError(LifecycleIssueTransitionRequiresExternal, from, to)
	}
	if lifecycleTransitionAllowed(from, to) {
		return nil
	}
	return lifecycleTransitionError(LifecycleIssueTransitionUnsupported, from, to)
}

// LifecycleStatusSatisfiesDependency reports whether a persisted status
// satisfies dependent beads. Only closed satisfies dependents.
func LifecycleStatusSatisfiesDependency(status string) bool {
	return status == StatusClosed
}

// LifecycleDependenciesSatisfied reports whether every dependency is closed.
func LifecycleDependenciesSatisfied(deps []LifecycleDependencyState) bool {
	for _, dep := range deps {
		if !LifecycleStatusSatisfiesDependency(dep.Status) {
			return false
		}
	}
	return true
}

// EvaluateLifecycleQueue derives queue state from caller-provided facts. Legacy
// lifecycle labels are reported as warnings only; they never choose the bucket.
func EvaluateLifecycleQueue(f LifecycleQueueFacts) LifecycleQueueDecision {
	decision := LifecycleQueueDecision{
		DependenciesSatisfied: LifecycleDependenciesSatisfied(f.Dependencies),
		SatisfiesDependents:   LifecycleStatusSatisfiesDependency(f.Status),
	}
	decision.Warnings = append(decision.Warnings, lifecycleLegacyLabelWarnings(f.LegacyLabels)...)
	for _, warning := range f.LegacyMigrationWarnings {
		trimmed := strings.TrimSpace(warning)
		if trimmed == "" {
			continue
		}
		decision.Issues = append(decision.Issues, LifecycleIssue{
			Code:   LifecycleIssueLegacyMigrationCompatibility,
			Detail: trimmed,
		})
		decision.Warnings = append(decision.Warnings, trimmed)
	}

	if err := validateLifecycleStatus(f.Status); err != nil {
		decision.Bucket = LifecycleBucketInvalid
		decision.Issues = append(decision.Issues, LifecycleIssue{
			Code:   LifecycleIssueInvalidStatus,
			Detail: err.Error(),
		})
		return decision
	}

	switch f.Status {
	case StatusClosed:
		decision.Bucket = LifecycleBucketClosedTerminal
	case StatusCancelled:
		decision.Bucket = LifecycleBucketCancelledTerminal
	case StatusProposed:
		decision.Bucket = LifecycleBucketProposed
		decision.OperatorAttention = true
	case StatusInProgress:
		if f.ClaimFresh {
			decision.Bucket = LifecycleBucketClaimed
			return decision
		}
		decision = evaluateOpenLifecycleQueue(f, decision)
	case StatusBlocked:
		decision.Bucket = LifecycleBucketBlockedExternal
		decision.ExternalBlockerReason = strings.TrimSpace(f.ExternalBlockerReason)
		if decision.ExternalBlockerReason == "" {
			decision.Issues = append(decision.Issues, LifecycleIssue{
				Code:   LifecycleIssueBlockedMissingExternalReason,
				Detail: "blocked status requires an explicit external blocker reason",
			})
		}
	case StatusOpen:
		if f.ClaimFresh {
			decision.Bucket = LifecycleBucketClaimed
			return decision
		}
		decision = evaluateOpenLifecycleQueue(f, decision)
	}
	return decision
}

func evaluateOpenLifecycleQueue(f LifecycleQueueFacts, decision LifecycleQueueDecision) LifecycleQueueDecision {
	if !decision.DependenciesSatisfied {
		decision.Bucket = LifecycleBucketWaitingDependencies
		return decision
	}
	if strings.TrimSpace(f.SupersededBy) != "" {
		decision.Bucket = LifecycleBucketSuperseded
		return decision
	}
	if f.EpicContainer {
		decision.Bucket = LifecycleBucketEpicContainer
		return decision
	}
	if f.RetryCooldownActive {
		decision.Bucket = LifecycleBucketRetryCooldown
		return decision
	}
	if f.ExecutionEligibleKnown && !f.ExecutionEligible {
		decision.Bucket = LifecycleBucketNotEligible
		return decision
	}
	decision.Bucket = LifecycleBucketReady
	decision.WorkerEligible = true
	return decision
}

func validateLifecycleStatus(status string) error {
	if IsCanonicalStatus(status) {
		return nil
	}
	return fmt.Errorf("%s: %q", LifecycleIssueInvalidStatus, status)
}

func lifecycleTransitionAllowed(from, to string) bool {
	switch from {
	case StatusProposed:
		return to == StatusOpen || to == StatusCancelled
	case StatusOpen:
		return to == StatusInProgress || to == StatusBlocked || to == StatusProposed || to == StatusCancelled
	case StatusInProgress:
		return to == StatusOpen || to == StatusClosed || to == StatusBlocked || to == StatusProposed
	case StatusBlocked:
		return to == StatusOpen || to == StatusProposed || to == StatusCancelled
	default:
		return false
	}
}

func lifecycleTransitionError(code LifecycleIssueCode, from, to string) error {
	return fmt.Errorf("%s: %s -> %s", code, from, to)
}

package bead

import (
	"fmt"
	"sort"
	"strings"
)

// BlockReasonCode is the closed taxonomy of reasons an open bead is non-ready
// in the idle-path diagnosis pass. The full set is defined by FEAT-010
// §Idle-Path Diagnosis and Auto-Remediation; new codes require that spec to
// be updated.
type BlockReasonCode string

const (
	ReasonSupersededPendingClose              BlockReasonCode = "superseded_pending_close"
	ReasonClosureCandidateMisclassified       BlockReasonCode = "closure_candidate_misclassified"
	ReasonDeadIntermediateAllChildrenClosed   BlockReasonCode = "dead_intermediate_all_children_closed"
	ReasonDeadIntermediateOpenChildrenPending BlockReasonCode = "dead_intermediate_open_children_pending"
	ReasonEpicOfEpic                          BlockReasonCode = "epic_of_epic"
	ReasonDepBlockedBy                        BlockReasonCode = "dep_blocked_by"
	ReasonGenuinelyNeedsDecomposition         BlockReasonCode = "genuinely_needs_decomposition"
	ReasonParentChildStateConflict            BlockReasonCode = "parent_child_state_conflict"
	ReasonClaimedInProgress                   BlockReasonCode = "claimed_in_progress"
	ReasonProviderRouteUnavailable            BlockReasonCode = "provider_route_unavailable"
	ReasonGatedByBudgetOrCooldown             BlockReasonCode = "gated_by_budget_or_cooldown"
	ReasonMalformedParentOrDepRef             BlockReasonCode = "malformed_parent_or_dep_ref"
	ReasonDependencyCycle                     BlockReasonCode = "dependency_cycle"
	ReasonClosedOrMissingParent               BlockReasonCode = "closed_or_missing_parent"
	ReasonStaleGraphIndex                     BlockReasonCode = "stale_graph_index"
	ReasonAutoRemediationExhausted            BlockReasonCode = "auto_remediation_exhausted"
	ReasonNoDiagnosis                         BlockReasonCode = "no_diagnosis"
)

// BlockReason is a per-bead diagnosis of why a bead is non-ready. Detail is a
// human-readable string suitable for surfacing to operators; CitedIDs lists
// other bead IDs the reason references (deps, supersession targets, parents,
// cycle participants).
type BlockReason struct {
	Code     BlockReasonCode
	Detail   string
	CitedIDs []string
}

// Diagnose returns the first matching BlockReason for b according to the
// FEAT-010 §Idle-Path Diagnosis and Auto-Remediation taxonomy. The caller
// must pre-build the indexes:
//
//   - childIndex: parent_id -> every child bead (any status). Root beads are
//     keyed under the empty string. Diagnose also uses childIndex as the
//     global bead lookup; every referenced bead (supersession target, dep
//     target, parent) must appear in some entry for Diagnose to verify its
//     state.
//   - openChildIndex: parent_id -> open child beads only.
//   - depIndex: bead_id -> outgoing Dependency entries for that bead. Used
//     for global cycle detection across the dep DAG.
//
// Diagnose is pure: it performs no I/O, does not consult global state, and
// does not mutate its inputs.
func Diagnose(
	b Bead,
	childIndex map[string][]Bead,
	openChildIndex map[string][]Bead,
	depIndex map[string][]Dependency,
) BlockReason {
	// 1. superseded_pending_close
	if y := supersedingTargetID(b); y != "" {
		if target, ok := lookupBead(childIndex, y); ok && target.Status == StatusClosed {
			return BlockReason{
				Code:     ReasonSupersededPendingClose,
				Detail:   fmt.Sprintf("superseded by closed bead %s", y),
				CitedIDs: []string{y},
			}
		}
	}

	total := len(childIndex[b.ID])
	open := len(openChildIndex[b.ID])

	// 2. closure_candidate_misclassified — epic with closure-ready child set
	if isEpicBead(b) && total > 0 && open == 0 {
		return BlockReason{
			Code:   ReasonClosureCandidateMisclassified,
			Detail: fmt.Sprintf("epic %s has %d children, none open", b.ID, total),
		}
	}

	// 3 & 4. dead_intermediate_* — bead opted out of execution
	if eligible, set := lifecycleExecutionEligible(b); set && !eligible {
		if total > 0 && open == 0 {
			return BlockReason{
				Code:   ReasonDeadIntermediateAllChildrenClosed,
				Detail: "execution-eligible=false; all children closed",
			}
		}
		if open > 0 {
			ids := beadIDsFrom(openChildIndex[b.ID])
			return BlockReason{
				Code:     ReasonDeadIntermediateOpenChildrenPending,
				Detail:   fmt.Sprintf("execution-eligible=false; %d open child(ren) pending", open),
				CitedIDs: ids,
			}
		}
	}

	// 5. epic_of_epic — only open descendants are themselves epics
	if open > 0 {
		openChildren := openChildIndex[b.ID]
		if allEpicBeads(openChildren) {
			return BlockReason{
				Code:     ReasonEpicOfEpic,
				Detail:   "only open children are themselves epics",
				CitedIDs: beadIDsFrom(openChildren),
			}
		}
	}

	// 6. dep_blocked_by — unresolved outgoing deps
	if blockers := openDepBlockers(b, childIndex); len(blockers) > 0 {
		ids := make([]string, 0, len(blockers))
		details := make([]string, 0, len(blockers))
		for _, blk := range blockers {
			ids = append(ids, blk.ID)
			details = append(details, fmt.Sprintf("%s(status=%s)", blk.ID, blk.Status))
		}
		return BlockReason{
			Code:     ReasonDepBlockedBy,
			Detail:   "dep_blocked_by:" + strings.Join(details, ","),
			CitedIDs: ids,
		}
	}

	// 7. genuinely_needs_decomposition
	if isEpicBead(b) && total == 0 && !hasDecompositionOverrideLabel(b) {
		return BlockReason{
			Code:   ReasonGenuinelyNeedsDecomposition,
			Detail: "epic with no children and no manual-hold/no-auto-decompose/container override",
		}
	}

	// 8. parent_child_state_conflict
	if msg := parentChildConflict(b, childIndex); msg != "" {
		return BlockReason{
			Code:   ReasonParentChildStateConflict,
			Detail: msg,
		}
	}

	// 9. claimed_in_progress
	if b.Status == StatusInProgress {
		return BlockReason{
			Code:   ReasonClaimedInProgress,
			Detail: "bead currently claimed by an active worker",
		}
	}

	// 10. provider_route_unavailable
	if isProviderRouteUnavailable(b) {
		return BlockReason{
			Code:   ReasonProviderRouteUnavailable,
			Detail: "last dispatch: " + providerRouteHint(b),
		}
	}

	// 11. gated_by_budget_or_cooldown
	if gate := budgetOrCooldownGate(b); gate != "" {
		return BlockReason{
			Code:   ReasonGatedByBudgetOrCooldown,
			Detail: gate,
		}
	}

	// 12. malformed_parent_or_dep_ref
	if msg, cited := malformedRef(b, childIndex); msg != "" {
		return BlockReason{
			Code:     ReasonMalformedParentOrDepRef,
			Detail:   msg,
			CitedIDs: cited,
		}
	}

	// 13. dependency_cycle
	if cycle := detectDepCycle(b.ID, depIndex); len(cycle) > 0 {
		return BlockReason{
			Code:     ReasonDependencyCycle,
			Detail:   "cycle: " + strings.Join(cycle, "->"),
			CitedIDs: cycle,
		}
	}

	// 14. closed_or_missing_parent
	if b.Parent != "" {
		if parent, ok := lookupBead(childIndex, b.Parent); ok && parent.Status == StatusClosed {
			return BlockReason{
				Code:     ReasonClosedOrMissingParent,
				Detail:   fmt.Sprintf("parent %s is closed", b.Parent),
				CitedIDs: []string{b.Parent},
			}
		}
	}

	// 15. stale_graph_index
	if msg := staleIndexDisagreement(b, childIndex, openChildIndex); msg != "" {
		return BlockReason{
			Code:   ReasonStaleGraphIndex,
			Detail: msg,
		}
	}

	// 16. auto_remediation_exhausted
	if isAutoRemediationExhausted(b) {
		return BlockReason{
			Code:   ReasonAutoRemediationExhausted,
			Detail: "auto-remediation attempts cap hit or cooldown active",
		}
	}

	// 17. no_diagnosis (fallback)
	return BlockReason{
		Code:   ReasonNoDiagnosis,
		Detail: "no diagnosis matched; surface as bug",
	}
}

// supersedingTargetID returns the ID of the bead that supersedes b, either
// from the canonical `superseded-by` extra field or from a
// `superseded-by:<id>` label. Empty string means not superseded.
func supersedingTargetID(b Bead) string {
	if id := lifecycleSupersededBy(b); id != "" {
		return id
	}
	for _, l := range b.Labels {
		if strings.HasPrefix(l, "superseded-by:") {
			if id := strings.TrimSpace(strings.TrimPrefix(l, "superseded-by:")); id != "" {
				return id
			}
		}
	}
	return ""
}

// lookupBead scans the childIndex (which holds every bead, keyed by parent
// ID with roots under "") for the bead with the given ID.
func lookupBead(childIndex map[string][]Bead, id string) (Bead, bool) {
	if id == "" {
		return Bead{}, false
	}
	for _, beads := range childIndex {
		for _, b := range beads {
			if b.ID == id {
				return b, true
			}
		}
	}
	return Bead{}, false
}

func beadIDsFrom(beads []Bead) []string {
	out := make([]string, 0, len(beads))
	for _, b := range beads {

